using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Retrieve a configuration value by key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up")] string key)
    {
        var config = new Dictionary<string, string>
        {
            ["app:name"] = "HttpMcpServer",
            ["app:version"] = "1.0.0",
            ["app:environment"] = "production",
            ["feature:darkMode"] = "true",
            ["feature:maxRetries"] = "3"
        };

        return config.TryGetValue(key, out var value)
            ? value
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "Application Settings",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var settings = new
        {
            Application = new { Name = "HttpMcpServer", Version = "1.0.0" },
            Features = new { DarkMode = true, MaxRetries = 3, Timeout = 30 },
            Endpoints = new { Api = "https://api.example.com", Docs = "https://docs.example.com" }
        };

        return JsonSerializer.Serialize(settings, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/features",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns current feature flag settings.")]
    public static string GetFeatureFlags()
    {
        var flags = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false,
            ["analytics"] = true,
            ["notifications"] = true
        };

        return JsonSerializer.Serialize(flags, new JsonSerializerOptions { WriteIndented = true });
    }
}

